  ('police-b20a8cf8-moex-00424', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '離子流動檢測儀（IMS）可應用於海關、政府機構或公共場所等地方，藉以檢測現場器具是否有被裝填火', '["將待測物離子化，而放射源最後衰變成為", "", "、", "分別為下列何者？"]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00425', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '影像光譜比對儀（VideoSpectralComparator;VSC）可用以鑑識遭竄改之圖文資料，關於該儀器之光', '["可選擇紅外線反射光（Infrared Reflectance）光源", "可選擇紅外線冷光 （InfraredLuminescence）光源", "可選擇紫外線（Ultravioletlight）光源", "可選用適當濾鏡，以紅 外線感光攝影機顯像  ⑤可選擇適當濾鏡，以紫外線感光攝影機顯像，下列何者正確？"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00426', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '命案現場地板找尋到一個血滴，量測該血痕之長寬並計算出其sinθ值（血斑寬度除以血斑長度） 為 /2，該血滴撞擊地板之角度θ為：', '["15度", "30度", "45度", "60度 √2"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00427', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '塑膠炸藥乃恐怖組織常用的爆炸物，其中塞姆汀（Semtex）與C-4常以空運走私。塞姆汀（Semtex）', '["和", "混合成一種聚合物及油類所組成；C-4則由", "以及聚合物、可塑劑、燃油等所組成", "、"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00428', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '民眾檢舉某住宅處疑似有製毒販賣之不法行為，警方抵達後發現該處有各種設備與多種化學試 劑，諸如活性炭、濃氨水、乙醇、鹽酸及盛裝羥亞胺（Hydroxylimine）之袋子。據此，請研判該 處所最有可能是製造下列何種毒品？', '["搖頭丸（MDMA）", "K他命（Ketamine）", "甲基安非他命（Methamphetamine）", "PMA（para-Methoxyamphetamine）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00429', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '四種跡證之分析順序如下：玻璃（分析無機成分）、纖維染料（分析有機成分）、血液（分析酵 素蛋白型）、藥毒物（分析有機成分）。下列最正確的儀器配對為：', '["感應耦合電漿質譜儀（ICP/MS）、液相層析質譜儀（LC/MS）、電泳（electrophoresis）、氣相 層析質譜儀（GC/MS）", "偏光顯微鏡、紅外線光譜（FTIR）、酵素免疫分析（ELISA）、紫外光/可見光光譜儀（UV/VIS）", "原子吸收光譜法（AAS）、拉曼光譜儀、電泳（electrophoresis）、中子活化分析（NAA）", "偏光顯微鏡、熱裂解氣相層析質譜儀（Py-GC/MS）、血液生化分析儀（Clinical Chemistry Analyzer）、液相層析質譜儀（LC/MS）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00430', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於刑事DNA的分析步驟：①DNA定量（quantitation）  ②DNA萃取（extraction）  ③PCR產', '["PCR產物複製  ⑤機率統計分析  ⑥基因型別研判。其步驟次序下 列何者最為適當？", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00431', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '使用醯胺黑（Amido Black）試劑顯現血跡鞋印，係將血液中的①染色，經過清洗後，於可見光', '["色。使用瞬間接著劑（superglue）顯現金屬門把上之潛伏指紋，其結 果將呈現", "色", "、", "、"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00432', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於槍擊現場之射擊殘跡（GSR）檢測：①若該GSR含有Pb元素，使用sodiumrhodizonate 水', '["若該GSR含有亞硝酸根，使用Walker’s test檢測之，呈現之顏 色為？", "若該GSR含五價Sb，使用rhodamineB在濃鹽酸溶液下，生成之沉澱顏色為？", "、", "、"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00433', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於現場檢測儀器之顯現原理或使用方法的敘述：①「現場勘察線性光源產生器」係以低角度之', '["「反射式紫外光影像系統（Reflected UltravioletImagingSystem，RUVIS）」係以紫外光激發物證致使產生螢光", "「靜電足跡採取器 （electrostaticdustprintlifter）」也能應用於金屬面的鞋印痕之採取", "「反斯托克斯（anti-stokes） 指紋拍照系統」係以紅外線作為光源，適用於吸水透氣之物面，下列何者正確？", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
